// // This module implements a D flip-flop with synchronous reset functionality.
module d_ff_async_reset (
  input clk,
  input d,
  input r,
  output reg q
);

  always @(posedge clk or posedge r) begin
    if (r) begin
      q <= 1'b0;
    end else begin
      q <= d;
    end
  end

endmodule
